func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    xInt := int(x)
    yInt := int(y)
    kInt := int(k)

    // Extract submatrix
    submatrix := make([][]int64, kInt)
    for i := 0; i < kInt; i++ {
        submatrix[i] = make([]int64, kInt)
        for j := 0; j < kInt; j++ {
            submatrix[i][j] = grid[xInt+i][yInt+j]
        }
    }

    // Reverse the submatrix
    reversedSubmatrix := make([][]int64, kInt)
    for i := 0; i < kInt; i++ {
        reversedSubmatrix[kInt - 1 - i] = submatrix[i]
    }

    // Replace the rows in the original grid
    for i := 0; i < kInt; i++ {
        rowIdx := xInt + i
        originalRow := grid[rowIdx]
        new_row := make([]int64, len(originalRow))
        copy(new_row, originalRow[:yInt])
        copy(new_row[yInt:yInt+kInt], reversedSubmatrix[i])
        copy(new_row[yInt+kInt:], originalRow[yInt+kInt:])
        grid[rowIdx] = new_row
    }

    return grid
}
